#### **ChannelOutboundAdapter** - Sending Messages
How messages are delivered to the platform:

```typescript
type ChannelOutboundAdapter = {
  base?: {
    deliveryMode: "direct" | "queue" | "stream";
    textChunkLimit?: number;
    chunker?: (text: string, limit: number) => string[];
    chunkerMode?: "plain" | "markdown" | "html";
    pollMaxOptions?: number;
    shouldSuppressLocalPayloadPrompt?: (ctx: any) => boolean;
    beforeDeliverPayload?: (ctx: any) => Promise<void>;
    shouldSkipPlainTextSanitization?: (ctx: any) => boolean;
    sendPayload: (params: OutboundPayloadParams) => Promise<OutboundDeliveryResult>;
