  attachedResults?: {
    channel: string;
    sendText(params: OutboundTextParams): Promise<{ messageId?: string }>;
    sendMedia(params: OutboundMediaParams): Promise<{ messageId?: string }>;
    sendPoll(params: OutboundPollParams): Promise<{ messageId?: string }>;
  };
};
