export function listIrcAccountIds(cfg: OpenClawConfig): string[] {
  // Return ["default"] or Object.keys(cfg.channels?.irc?.accounts ?? {})
}

export function resolveDefaultIrcAccountId(cfg: OpenClawConfig): string {
  // Return cfg.channels?.irc?.defaultAccount ?? "default"
}

export function resolveIrcAccount(params: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedIrcAccount {
  const accountId = params.accountId ?? resolveDefaultIrcAccountId(params.cfg);
  const accounts = params.cfg.channels?.irc?.accounts ?? {};
  const accountConfig = accounts[accountId] ?? params.cfg.channels?.irc ?? {};
  return {
    accountId,
    configured: !!(accountConfig.host && accountConfig.nick),
    enabled: accountConfig.enabled !== false,
    host: accountConfig.host ?? "",
    // ... resolve all config fields
  };
}
```

