346	/**
347	 * Validate and normalize a private key (accepts hex or nsec format)
348	 */
349	export function validatePrivateKey(key: string): Uint8Array {
350	  const trimmed = key.trim();
351	
352	  // Handle nsec (bech32) format
353	  if (trimmed.startsWith("nsec1")) {
354	    const decoded = nip19.decode(trimmed);
355	    if (decoded.type !== "nsec") {
356	      throw new Error("Invalid nsec key: wrong type");
357	    }
358	    return decoded.data;
359	  }
360	
361	  // Handle hex format
362	  if (!/^[0-9a-fA-F]{64}$/.test(trimmed)) {
363	    throw new Error("Private key must be 64 hex characters or nsec bech32 format");
364	  }
365	
366	  // Convert hex string to Uint8Array
367	  const bytes = new Uint8Array(32);
368	  for (let i = 0; i < 32; i++) {
369	    bytes[i] = parseInt(trimmed.slice(i * 2, i * 2 + 2), 16);
370	  }
371	  return bytes;
372	}
