75	
76	async function withPublishLock<T>(accountId: string, fn: () => Promise<T>): Promise<T> {
77	  // Atomic mutex using promise chaining - prevents TOCTOU race condition
78	  const prev = publishLocks.get(accountId) ?? Promise.resolve();
79	  let resolve: () => void;
80	  const next = new Promise<void>((r) => {
81	    resolve = r;
82	  });
83	  // Atomically replace the lock before awaiting - any concurrent request
84	  // will now wait on our `next` promise
85	  publishLocks.set(accountId, next);
86	
87	  // Wait for previous operation to complete
88	  await prev.catch(() => {});
89	
90	  try {
91	    return await fn();
92	  } finally {
93	    resolve!();
94	    // Clean up if we're the last in chain
95	    if (publishLocks.get(accountId) === next) {
96	      publishLocks.delete(accountId);
97	    }
98	  }
99	}
