2	 * LRU-based seen event tracker with TTL support.
3	 * Prevents unbounded memory growth under high load or abuse.
4	 */
5	
6	export interface SeenTrackerOptions {
7	  /** Maximum number of entries to track (default: 100,000) */
8	  maxEntries?: number;
9	  /** TTL in milliseconds (default: 1 hour) */
10	  ttlMs?: number;
11	  /** Prune interval in milliseconds (default: 10 minutes) */
12	  pruneIntervalMs?: number;
13	}
14	
15	export interface SeenTracker {
16	  /** Check if an ID has been seen (also marks it as seen if not) */
17	  has: (id: string) => boolean;
18	  /** Mark an ID as seen */
19	  add: (id: string) => void;
20	  /** Check if ID exists without marking */
21	  peek: (id: string) => boolean;
22	  /** Delete an ID */
23	  delete: (id: string) => void;
24	  /** Clear all entries */
25	  clear: () => void;
26	  /** Get current size */
27	  size: () => number;
28	  /** Stop the pruning timer */
29	  stop: () => void;
30	  /** Pre-seed with IDs (useful for restart recovery) */
31	  seed: (ids: string[]) => void;
32	}
33	
34	interface Entry {
35	  seenAt: number;
36	  // For LRU: track order via doubly-linked list
37	  prev: string | null;
38	  next: string | null;
39	}
40	
41	/**
42	 * Create a new seen tracker with LRU eviction and TTL expiration.
43	 */
44	export function createSeenTracker(options?: SeenTrackerOptions): SeenTracker {
45	  const maxEntries = options?.maxEntries ?? 100_000;
46	  const ttlMs = options?.ttlMs ?? 60 * 60 * 1000; // 1 hour
47	  const pruneIntervalMs = options?.pruneIntervalMs ?? 10 * 60 * 1000; // 10 minutes
48	
49	  // Main storage
50	  const entries = new Map<string, Entry>();
51	
52	  // LRU tracking: head = most recent, tail = least recent
53	  let head: string | null = null;
54	  let tail: string | null = null;
55	
56	  // Move an entry to the front (most recently used)
57	  function moveToFront(id: string): void {
58	    const entry = entries.get(id);
59	    if (!entry) {
60	      return;
61	    }
62	
63	    // Already at front
64	    if (head === id) {
65	      return;
66	    }
67	
68	    // Remove from current position
69	    if (entry.prev) {
70	      const prevEntry = entries.get(entry.prev);
71	      if (prevEntry) {
72	        prevEntry.next = entry.next;
73	      }
74	    }
75	    if (entry.next) {
76	      const nextEntry = entries.get(entry.next);
77	      if (nextEntry) {
78	        nextEntry.prev = entry.prev;
79	      }
80	    }
81	
82	    // Update tail if this was the tail
83	    if (tail === id) {
84	      tail = entry.prev;
85	    }
86	
87	    // Move to front
88	    entry.prev = null;
89	    entry.next = head;
90	    if (head) {
91	      const headEntry = entries.get(head);
92	      if (headEntry) {
93	        headEntry.prev = id;
94	      }
95	    }
96	    head = id;
97	
98	    // If no tail, this is also the tail
99	    if (!tail) {
100	      tail = id;
101	    }
102	  }
103	
104	  // Remove an entry from the linked list
105	  function removeFromList(id: string): void {
106	    const entry = entries.get(id);
107	    if (!entry) {
108	      return;
109	    }
110	
111	    if (entry.prev) {
112	      const prevEntry = entries.get(entry.prev);
113	      if (prevEntry) {
114	        prevEntry.next = entry.next;
115	      }
116	    } else {
117	      head = entry.next;
118	    }
119	
120	    if (entry.next) {
121	      const nextEntry = entries.get(entry.next);
122	      if (nextEntry) {
123	        nextEntry.prev = entry.prev;
124	      }
125	    } else {
126	      tail = entry.prev;
127	    }
128	  }
129	
130	  // Evict the least recently used entry
131	  function evictLRU(): void {
132	    if (!tail) {
133	      return;
134	    }
135	    const idToEvict = tail;
136	    removeFromList(idToEvict);
137	    entries.delete(idToEvict);
138	  }
139	
140	  function insertAtFront(id: string, seenAt: number): void {
141	    const newEntry: Entry = {
142	      seenAt,
143	      prev: null,
144	      next: head,
145	    };
146	
147	    if (head) {
148	      const headEntry = entries.get(head);
149	      if (headEntry) {
150	        headEntry.prev = id;
151	      }
152	    }
153	
154	    entries.set(id, newEntry);
155	    head = id;
156	    if (!tail) {
157	      tail = id;
158	    }
159	  }
160	
161	  // Prune expired entries
162	  function pruneExpired(): void {
163	    const now = Date.now();
164	    const toDelete: string[] = [];
165	
166	    for (const [id, entry] of entries) {
167	      if (now - entry.seenAt > ttlMs) {
168	        toDelete.push(id);
169	      }
170	    }
171	
172	    for (const id of toDelete) {
173	      removeFromList(id);
174	      entries.delete(id);
175	    }
176	  }
177	
178	  // Start pruning timer
179	  let pruneTimer: ReturnType<typeof setInterval> | undefined;
180	  if (pruneIntervalMs > 0) {
181	    pruneTimer = setInterval(pruneExpired, pruneIntervalMs);
182	    // Don't keep process alive just for pruning
183	    if (pruneTimer.unref) {
184	      pruneTimer.unref();
185	    }
186	  }
187	
188	  function add(id: string): void {
189	    const now = Date.now();
190	
191	    // If already exists, update and move to front
192	    const existing = entries.get(id);
193	    if (existing) {
194	      existing.seenAt = now;
195	      moveToFront(id);
196	      return;
197	    }
198	
199	    // Evict if at capacity
200	    while (entries.size >= maxEntries) {
201	      evictLRU();
202	    }
203	
204	    insertAtFront(id, now);
205	  }
206	
207	  function has(id: string): boolean {
208	    const entry = entries.get(id);
209	    if (!entry) {
210	      add(id);
211	      return false;
212	    }
213	
214	    // Check if expired
215	    if (Date.now() - entry.seenAt > ttlMs) {
216	      removeFromList(id);
217	      entries.delete(id);
218	      add(id);
219	      return false;
220	    }
221	
222	    // Mark as recently used
223	    entry.seenAt = Date.now();
224	    moveToFront(id);
225	    return true;
226	  }
227	
228	  function peek(id: string): boolean {
229	    const entry = entries.get(id);
230	    if (!entry) {
231	      return false;
232	    }
233	
234	    // Check if expired
235	    if (Date.now() - entry.seenAt > ttlMs) {
236	      removeFromList(id);
237	      entries.delete(id);
238	      return false;
239	    }
240	
241	    return true;
242	  }
243	
244	  function deleteEntry(id: string): void {
245	    if (entries.has(id)) {
246	      removeFromList(id);
247	      entries.delete(id);
248	    }
249	  }
250	
251	  function clear(): void {
252	    entries.clear();
253	    head = null;
254	    tail = null;
255	  }
256	
257	  function size(): number {
258	    return entries.size;
259	  }
260	
261	  function stop(): void {
262	    if (pruneTimer) {
263	      clearInterval(pruneTimer);
264	      pruneTimer = undefined;
265	    }
266	  }
267	
268	  function seed(ids: string[]): void {
269	    const now = Date.now();
270	    // Seed in reverse order so first IDs end up at front
271	    for (let i = ids.length - 1; i >= 0; i--) {
272	      const id = ids[i];
273	      if (!entries.has(id) && entries.size < maxEntries) {
274	        insertAtFront(id, now);
275	      }
276	    }
277	  }
278	
279	  return {
280	    has,
281	    add,
282	    peek,
283	    delete: deleteEntry,
284	    clear,
285	    size,
286	    stop,
287	    seed,
288	  };
289	}
