247	function hasNonLoopbackForwardedClient(req: IncomingMessage): boolean {
248	  const forwardedFor = firstHeaderValue(req.headers["x-forwarded-for"]);
249	  if (forwardedFor) {
250	    for (const hop of forwardedFor.split(",")) {
251	      const candidate = normalizeIpCandidate(hop);
252	      if (!candidate) {
253	        continue;
254	      }
255	      if (!isLoopbackRemoteAddress(candidate)) {
256	        return true;
257	      }
258	    }
259	  }
260	
261	  const realIp = firstHeaderValue(req.headers["x-real-ip"]);
262	  if (realIp) {
263	    const candidate = normalizeIpCandidate(realIp);
264	    if (candidate && !isLoopbackRemoteAddress(candidate)) {
265	      return true;
266	    }
267	  }
268	
269	  return false;
270	}
