323	  ctx: NostrProfileHttpContext,
324	): (req: IncomingMessage, res: ServerResponse) => Promise<boolean> {
325	  return async (req, res) => {
326	    const url = new URL(req.url ?? "/", `http://${req.headers.host ?? "localhost"}`);
327	
328	    // Only handle /api/channels/nostr/:accountId/profile paths
329	    if (!url.pathname.startsWith("/api/channels/nostr/")) {
330	      return false;
331	    }
332	
333	    const accountId = parseAccountIdFromPath(url.pathname);
334	    if (!accountId) {
335	      return false;
336	    }
337	
338	    const isImport = url.pathname.endsWith("/profile/import");
339	    const isProfilePath = url.pathname.endsWith("/profile") || isImport;
340	
341	    if (!isProfilePath) {
342	      return false;
343	    }
344	
345	    // Handle different HTTP methods
346	    try {
347	      if (req.method === "GET" && !isImport) {
348	        return await handleGetProfile(accountId, ctx, res);
349	      }
350	
351	      if (req.method === "PUT" && !isImport) {
352	        return await handleUpdateProfile(accountId, ctx, req, res);
353	      }
354	
355	      if (req.method === "POST" && isImport) {
356	        return await handleImportProfile(accountId, ctx, req, res);
357	      }
358	
359	      // Method not allowed
360	      sendJson(res, 405, { ok: false, error: "Method not allowed" });
361	      return true;
362	    } catch (err) {
363	      ctx.log?.error(`Profile HTTP error: ${String(err)}`);
364	      sendJson(res, 500, { ok: false, error: "Internal server error" });
