### `extensions/pulseboard/src/normalize.ts`
Target normalization for PulseBoard addresses:
- **Board targets**: `#boardname`, `board:boardname` → canonical `board:boardname`
- **DM targets**: `@userid`, `dm:userid`, or bare `userid` → canonical `dm:userid`

```typescript
// Returns canonical form or undefined if invalid
export function normalizePulseboardTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) return undefined;

  // Explicit board prefix
  if (trimmed.startsWith("board:")) return trimmed;
  // # sigil → board
  if (trimmed.startsWith("#")) return `board:${trimmed.slice(1)}`;
  // Explicit dm prefix
  if (trimmed.startsWith("dm:")) return trimmed;
  // @ sigil → dm
  if (trimmed.startsWith("@")) return `dm:${trimmed.slice(1)}`;
  // Strip channel prefix if present
  if (trimmed.startsWith("pulseboard:")) return normalizePulseboardTarget(trimmed.slice(11));
  // Bare string — assume DM target
  return `dm:${trimmed}`;
}

// Returns true for board targets (canonical or # form)
export function isBoardTarget(target: string): boolean {
  return target.startsWith("board:") || target.startsWith("#");
}

// Returns true for dm targets
export function isDmTarget(target: string): boolean {
  return target.startsWith("dm:") || target.startsWith("@");
}

// Extracts the board name from canonical "board:name"
export function extractBoardName(target: string): string {
  return target.startsWith("board:") ? target.slice(6) : target.replace(/^#/, "");
}

// Extracts the user ID from canonical "dm:userid"
export function extractDmUserId(target: string): string {
  return target.startsWith("dm:") ? target.slice(3) : target.replace(/^@/, "");
}

// Normalize an allowlist entry (lowercase, strip prefixes)
export function normalizePulseboardAllowEntry(raw: string): string {
  return extractDmUserId(raw.trim().toLowerCase());
}

// Returns true if the input looks like a valid PulseBoard target ID
export function looksLikePulseboardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  return (
    trimmed.startsWith("#") ||
    trimmed.startsWith("@") ||
    trimmed.startsWith("board:") ||
    trimmed.startsWith("dm:") ||
    /^[a-z0-9_-]{2,64}$/i.test(trimmed)
  );
}
```

