### `extensions/pulseboard/src/inbound.ts`
Inbound message routing. Mirrors `extensions/irc/src/inbound.ts` but simplified (no group policy tiers — boards are either allowed or not). Receives a `PulseboardMessage`, checks DM policy / board allowlist, then dispatches to core.

```typescript
import {
  createChannelPairingController,
  dispatchInboundReplyWithBase,
} from "./runtime-api.js";
import { resolvePulseboardAccount } from "./accounts.js";
import { normalizePulseboardAllowEntry } from "./normalize.js";
import { sendMessagePulseboard } from "./send.js";
import { PAIRING_APPROVED_MESSAGE } from "./runtime-api.js";
import type { PulseboardMessage, CoreConfig, ResolvedPulseboardAccount } from "./types.js";
import type { RuntimeEnv } from "./runtime-api.js";

export type InboundPulseboardContext = {
  cfg: CoreConfig;
  accountId: string;
  account: ResolvedPulseboardAccount;
  runtime: RuntimeEnv;
  message: PulseboardMessage;
};

export async function handlePulseboardInbound(ctx: InboundPulseboardContext): Promise<void> {
  const { cfg, accountId, account, runtime, message } = ctx;

  // Determine routing target (canonical form)
  const target =
    message.type === "board" && message.boardName
      ? `board:${message.boardName}`
      : `dm:${message.senderId}`;

  const senderId = message.senderId;
  const dmPolicy = account.config.dmPolicy ?? "pairing";
  const allowFrom = (account.config.allowFrom ?? []).map((e) => normalizePulseboardAllowEntry(String(e)));
  const normalizedSender = normalizePulseboardAllowEntry(senderId);

  // Board messages: just dispatch (boards are subscribed intentionally)
  if (message.type === "board") {
    await dispatchInboundReplyWithBase({
      cfg,
      channel: "pulseboard",
      accountId,
      target,
      senderId,
      text: message.text,
      messageId: message.messageId,
      timestamp: message.timestamp,
      runtime,
    });
    return;
  }

  // DM message — apply DM policy
  if (dmPolicy === "disabled") {
    return;
  }

  if (dmPolicy === "open" || allowFrom.includes("*")) {
    await dispatchInboundReplyWithBase({
      cfg,
      channel: "pulseboard",
      accountId,
      target,
      senderId,
      text: message.text,
      messageId: message.messageId,
      timestamp: message.timestamp,
      runtime,
    });
    return;
  }

  const isAllowed =
    allowFrom.includes(normalizedSender) ||
    (dmPolicy === "allowlist" && allowFrom.includes("*"));

  if (isAllowed) {
    await dispatchInboundReplyWithBase({
      cfg,
      channel: "pulseboard",
      accountId,
      target,
      senderId,
      text: message.text,
      messageId: message.messageId,
      timestamp: message.timestamp,
      runtime,
    });
    return;
  }

  // Pairing mode: send approval challenge
  if (dmPolicy === "pairing") {
    const controller = createChannelPairingController({
      cfg,
      channel: "pulseboard",
      accountId,
      senderId,
      runtime,
    });
    const challenged = await controller.challengeIfNeeded();
    if (challenged) {
      await sendMessagePulseboard(`dm:${senderId}`, PAIRING_APPROVED_MESSAGE, {
        cfg,
        accountId,
      }).catch(() => {
        // best-effort pairing notification
      });
    }
  }
}
```

> **Note**: The exact signature of `dispatchInboundReplyWithBase` and `createChannelPairingController` must be verified from `extensions/irc/src/runtime-api.ts` and the corresponding plugin SDK sources. Adjust parameter shapes to match the actual API.

