### `extensions/pulseboard/src/accounts.ts`
Account resolution. Mirrors `extensions/irc/src/accounts.ts` pattern but simpler (no password file, no NickServ):

```typescript
import { DEFAULT_ACCOUNT_ID } from "./runtime-api.js";
import type { CoreConfig, PulseboardAccountConfig, ResolvedPulseboardAccount } from "./types.js";

export function listPulseboardAccountIds(cfg: CoreConfig): string[] {
  const pb = cfg.channels?.pulseboard;
  if (!pb) return [];
  const accountKeys = Object.keys(pb.accounts ?? {});
  return accountKeys.length > 0 ? accountKeys : [DEFAULT_ACCOUNT_ID];
}

export function resolveDefaultPulseboardAccountId(cfg: CoreConfig): string {
  return cfg.channels?.pulseboard?.defaultAccount ?? DEFAULT_ACCOUNT_ID;
}

export function resolvePulseboardAccount(params: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseboardAccount {
  const accountId = params.accountId ?? resolveDefaultPulseboardAccountId(params.cfg);
  const base = params.cfg.channels?.pulseboard ?? {};
  const perAccount: PulseboardAccountConfig =
    accountId === DEFAULT_ACCOUNT_ID
      ? {}
      : (params.cfg.channels?.pulseboard?.accounts?.[accountId] ?? {});
  const merged: PulseboardAccountConfig = { ...base, ...perAccount };

  const serverUrl = merged.serverUrl ?? "";
  const token = merged.token ?? "";
  const userId = merged.userId ?? "";

  return {
    accountId,
    enabled: merged.enabled !== false,
    configured: Boolean(serverUrl && token && userId),
    name: merged.name,
    serverUrl,
    token,
    userId,
    username: merged.username ?? userId,
    config: merged,
  };
}
```

