### `extensions/pulseboard/src/client.ts`
Fictional PulseBoard HTTP API client stub. Uses native `fetch`.

```typescript
import type { PulseboardMessage } from "./types.js";

// Fictional PulseBoard REST API base paths:
//   GET  /api/v1/updates?since=<timestamp>   → { messages: PulseboardMessage[] }
//   POST /api/v1/messages/direct             → { messageId: string }
//   POST /api/v1/messages/board/<boardName>  → { messageId: string }
//   GET  /api/v1/me                          → { userId: string, username: string }

export type PulseboardClientOptions = {
  serverUrl: string;
  token: string;
  userId: string;
};

export type PulseboardSendResult = {
  messageId: string;
};

export async function pulseboardFetch<T>(
  serverUrl: string,
  token: string,
  path: string,
  init?: RequestInit,
): Promise<T> {
  const url = `${serverUrl.replace(/\/$/, "")}${path}`;
  const res = await fetch(url, {
    ...init,
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
      ...(init?.headers ?? {}),
    },
  });
  if (!res.ok) {
    throw new Error(`PulseBoard API error ${res.status}: ${await res.text()}`);
  }
  return res.json() as Promise<T>;
}

// Poll for new messages since a given timestamp (unix ms)
export async function pollPulseboardUpdates(
  opts: PulseboardClientOptions,
  since: number,
  signal: AbortSignal,
): Promise<PulseboardMessage[]> {
  const data = await pulseboardFetch<{ messages: PulseboardMessage[] }>(
    opts.serverUrl,
    opts.token,
    `/api/v1/updates?since=${since}`,
    { signal },
  );
  return data.messages ?? [];
}

// Send a direct message to a user ID
export async function sendPulseboardDm(
  opts: PulseboardClientOptions,
  toUserId: string,
  text: string,
): Promise<PulseboardSendResult> {
  return pulseboardFetch<PulseboardSendResult>(opts.serverUrl, opts.token, "/api/v1/messages/direct", {
    method: "POST",
    body: JSON.stringify({ toUserId, text }),
  });
}

// Post a message to a named board
export async function sendPulseboardBoard(
  opts: PulseboardClientOptions,
  boardName: string,
  text: string,
): Promise<PulseboardSendResult> {
  return pulseboardFetch<PulseboardSendResult>(
    opts.serverUrl,
    opts.token,
    `/api/v1/messages/board/${encodeURIComponent(boardName)}`,
    { method: "POST", body: JSON.stringify({ text }) },
  );
}

// Probe API health — fetches /api/v1/me
export async function probePulseboardApi(
  opts: PulseboardClientOptions,
  signal?: AbortSignal,
): Promise<{ userId: string; username: string }> {
  return pulseboardFetch<{ userId: string; username: string }>(
    opts.serverUrl,
    opts.token,
    "/api/v1/me",
    { signal },
  );
}
```

