### `extensions/pulseboard/src/monitor.ts`
Polling loop that calls the PulseBoard updates API and routes messages. Mirrors `extensions/irc/src/monitor.ts` pattern with `AbortSignal`-driven teardown:

```typescript
import { pollPulseboardUpdates } from "./client.js";
import { resolvePulseboardAccount } from "./accounts.js";
import { handlePulseboardInbound } from "./inbound.js";
import { createAccountStatusSink } from "./runtime-api.js";
import type { CoreConfig } from "./types.js";
import type { RuntimeEnv } from "./runtime-api.js";

const POLL_INTERVAL_MS = 2000;

export type MonitorPulseboardOptions = {
  accountId: string;
  config: CoreConfig;
  runtime: RuntimeEnv;
  abortSignal: AbortSignal;
  statusSink?: ReturnType<typeof createAccountStatusSink>;
};

export async function monitorPulseboardProvider(opts: MonitorPulseboardOptions): Promise<void> {
  const { accountId, config, runtime, abortSignal } = opts;
  const account = resolvePulseboardAccount({ cfg: config, accountId });

  opts.statusSink?.setConnecting();

  let since = Date.now();

  opts.statusSink?.setConnected({ accountId, username: account.username });

  while (!abortSignal.aborted) {
    try {
      const messages = await pollPulseboardUpdates(
        { serverUrl: account.serverUrl, token: account.token, userId: account.userId },
        since,
        abortSignal,
      );

      for (const message of messages) {
        // Advance watermark to latest message timestamp
        if (message.timestamp > since) {
          since = message.timestamp;
        }
        // Skip messages from self
        if (message.senderId === account.userId) continue;

        await handlePulseboardInbound({
          cfg: config,
          accountId,
          account,
          runtime,
          message,
        }).catch((err: unknown) => {
          runtime.log?.warn(`[pulseboard:${accountId}] inbound error: ${String(err)}`);
        });
      }
    } catch (err) {
      if (abortSignal.aborted) break;
      runtime.log?.warn(`[pulseboard:${accountId}] poll error: ${String(err)}`);
    }

    // Sleep before next poll unless aborted
    await new Promise<void>((resolve) => {
      const timer = setTimeout(resolve, POLL_INTERVAL_MS);
      abortSignal.addEventListener("abort", () => {
        clearTimeout(timer);
        resolve();
      }, { once: true });
    });
  }

  opts.statusSink?.setDisconnected({ accountId });
}
```

> **Note**: `statusSink` method names (`setConnecting`, `setConnected`, `setDisconnected`) should be verified from `extensions/irc/src/monitor.ts` and the `createAccountStatusSink` API. Adjust to match actual interface.

