### `extensions/pulseboard/src/setup-surface.ts`
Setup adapter and wizard. Mirrors pattern from `extensions/irc/src/setup-core.ts` + `setup-surface.ts`. For simplicity, PulseBoard combines both into one file:

```typescript
import type { ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import {
  createStandardChannelSetupStatus,
  setSetupChannelEnabled,
} from "openclaw/plugin-sdk/setup";
import { DEFAULT_ACCOUNT_ID } from "./runtime-api.js";
import {
  listPulseboardAccountIds,
  resolveDefaultPulseboardAccountId,
  resolvePulseboardAccount,
} from "./accounts.js";
import type { CoreConfig } from "./types.js";

const channel = "pulseboard";

// Setup adapter: resolveAccountId + applyAccountConfig
// Used by both setup wizard and programmatic config
export const pulseboardSetupAdapter = {
  resolveAccountId: (params: { cfg: CoreConfig; input: Record<string, string> }) =>
    params.input.accountId ?? DEFAULT_ACCOUNT_ID,

  applyAccountConfig: (params: {
    cfg: CoreConfig;
    accountId: string;
    input: Record<string, string>;
  }): CoreConfig => {
    const { cfg, accountId, input } = params;
    const isDefault = accountId === DEFAULT_ACCOUNT_ID;
    const key = isDefault
      ? ["channels", "pulseboard"]
      : ["channels", "pulseboard", "accounts", accountId];

    // Deep-merge input fields into config at the right key
    let next: Record<string, unknown> = { ...(cfg as Record<string, unknown>) };
    let cursor = next;
    for (let i = 0; i < key.length - 1; i++) {
      const k = key[i]!;
      cursor[k] = { ...(cursor[k] as Record<string, unknown> ?? {}) };
      cursor = cursor[k] as Record<string, unknown>;
    }
    const leaf = key[key.length - 1]!;
    cursor[leaf] = {
      ...(cursor[leaf] as Record<string, unknown> ?? {}),
      ...(input.serverUrl ? { serverUrl: input.serverUrl } : {}),
      ...(input.token ? { token: input.token } : {}),
      ...(input.userId ? { userId: input.userId } : {}),
      ...(input.username ? { username: input.username } : {}),
    };
    return next as CoreConfig;
  },
};

// Setup wizard definition (interactive onboarding prompts)
export const pulseboardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channel,
    listAccountIds: listPulseboardAccountIds,
    resolveDefaultAccountId: resolveDefaultPulseboardAccountId,
    resolveAccount: (cfg, accountId) =>
      resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }),
    isConfigured: (account) => account.configured,
  }),
  textInputs: [
    {
      key: "serverUrl",
      label: "PulseBoard Server URL",
      placeholder: "https://api.pulseboard.example",
      help: "Base URL of your PulseBoard instance",
    },
    {
      key: "token",
      label: "API Token",
      sensitive: true,
      placeholder: "pb_tok_...",
      help: "Bearer token from your PulseBoard account settings",
    },
    {
      key: "userId",
      label: "User ID",
      placeholder: "user123",
      help: "Your bot's user ID on PulseBoard",
    },
    {
      key: "username",
      label: "Username (display name)",
      placeholder: "mybot",
      help: "Display name shown on PulseBoard",
    },
  ],
  dmPolicy: {
    default: "pairing",
    path: "channels.pulseboard.dmPolicy",
    options: ["open", "pairing", "allowlist", "disabled"],
  },
  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
};
```

> **Note**: The exact shape of `ChannelSetupWizard`, `createStandardChannelSetupStatus`, `textInputs` fields, and `dmPolicy` config must be verified from `extensions/irc/src/setup-surface.ts`. Adjust to match actual interface.

