(Add this small file referenced in channel.ts above)

```typescript
import { probePulseboardApi } from "./client.js";
import { resolvePulseboardAccount } from "./accounts.js";
import type { CoreConfig, PulseboardProbe } from "./types.js";

export async function probePulseboard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseboardProbe> {
  const account = resolvePulseboardAccount({ cfg, accountId: opts?.accountId });
  if (!account.configured) {
    return { ok: false, error: "missing serverUrl, token, or userId", serverUrl: account.serverUrl };
  }
  const started = Date.now();
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), opts?.timeoutMs ?? 8000);
  try {
    const me = await probePulseboardApi(
      { serverUrl: account.serverUrl, token: account.token, userId: account.userId },
      controller.signal,
    );
    return { ok: true, latencyMs: Date.now() - started, userId: me.userId, serverUrl: account.serverUrl };
  } catch (err) {
    return { ok: false, error: String(err), serverUrl: account.serverUrl };
  } finally {
    clearTimeout(timer);
  }
}
```

