### `extensions/pulseboard/src/channel.test.ts`
Basic unit tests covering account resolution, target normalization, and plugin shape:

```typescript
import { describe, it, expect } from "vitest";
import {
  resolvePulseboardAccount,
  listPulseboardAccountIds,
} from "./accounts.js";
import {
  normalizePulseboardTarget,
  isBoardTarget,
  isDmTarget,
  extractBoardName,
  extractDmUserId,
} from "./normalize.js";
import { pulseboardPlugin } from "./channel.js";
import type { CoreConfig } from "./types.js";

const baseCfg: CoreConfig = {
  channels: {
    pulseboard: {
      serverUrl: "https://pb.example",
      token: "tok_test",
      userId: "bot1",
      username: "testbot",
      dmPolicy: "pairing",
    },
  },
};

describe("accounts", () => {
  it("resolves default account", () => {
    const account = resolvePulseboardAccount({ cfg: baseCfg });
    expect(account.configured).toBe(true);
    expect(account.serverUrl).toBe("https://pb.example");
    expect(account.userId).toBe("bot1");
  });

  it("reports unconfigured when fields missing", () => {
    const account = resolvePulseboardAccount({ cfg: { channels: { pulseboard: {} } } });
    expect(account.configured).toBe(false);
  });

  it("lists account ids", () => {
    const ids = listPulseboardAccountIds(baseCfg);
    expect(ids).toContain("default");
  });
});

describe("normalize", () => {
  it("normalizes # board target", () => {
    expect(normalizePulseboardTarget("#general")).toBe("board:general");
  });

  it("normalizes board: prefix", () => {
    expect(normalizePulseboardTarget("board:tech")).toBe("board:tech");
  });

  it("normalizes @ dm target", () => {
    expect(normalizePulseboardTarget("@alice")).toBe("dm:alice");
  });

  it("normalizes dm: prefix", () => {
    expect(normalizePulseboardTarget("dm:bob")).toBe("dm:bob");
  });

  it("defaults bare string to dm", () => {
    expect(normalizePulseboardTarget("charlie")).toBe("dm:charlie");
  });

  it("isBoardTarget / isDmTarget", () => {
    expect(isBoardTarget("board:x")).toBe(true);
    expect(isDmTarget("dm:x")).toBe(true);
    expect(isBoardTarget("dm:x")).toBe(false);
  });

  it("extracts board name", () => {
    expect(extractBoardName("board:general")).toBe("general");
    expect(extractBoardName("#tech")).toBe("tech");
  });

  it("extracts dm user id", () => {
    expect(extractDmUserId("dm:alice")).toBe("alice");
    expect(extractDmUserId("@bob")).toBe("bob");
  });
});

describe("pulseboardPlugin shape", () => {
  it("has correct id", () => {
    expect(pulseboardPlugin.id).toBe("pulseboard");
  });

  it("supports direct and group chat types", () => {
    expect(pulseboardPlugin.capabilities.chatTypes).toContain("direct");
    expect(pulseboardPlugin.capabilities.chatTypes).toContain("group");
  });
});
