367	      [...new Set(entries.map((entry) => normalizeGroupEntry(entry)).filter(Boolean))] as string[],
368	    applyAllowlist: ({ cfg, accountId, resolved }) =>
369	      setIrcGroupAccess(
370	        cfg as CoreConfig,
371	        accountId,
372	        "allowlist",
373	        resolved as string[],
374	        normalizeGroupEntry,
375	      ),
376	  },
377	  allowFrom: createAllowFromSection({
378	    helpTitle: "IRC allowlist",
379	    helpLines: [
380	      "Allowlist IRC DMs by sender.",
381	      "Examples:",
382	      "- alice",
383	      "- alice!ident@example.org",
384	      "Multiple entries: comma-separated.",
385	    ],
386	    message: "IRC allowFrom (nick or nick!user@host)",
387	    placeholder: "alice, bob!ident@example.org",
388	    invalidWithoutCredentialNote: "Use an IRC nick or nick!user@host entry.",
389	    parseId: (raw) => {
390	      const normalized = normalizeIrcAllowEntry(raw);
391	      return normalized || null;
392	    },
393	    apply: async ({ cfg, allowFrom }) => setIrcAllowFrom(cfg as CoreConfig, allowFrom),
394	  }),
395	  finalize: async ({ cfg, accountId, prompter }) => {
396	    let next = cfg as CoreConfig;
397	
398	    const resolvedAfterGroups = resolveIrcAccount({ cfg: next, accountId });
399	    if (resolvedAfterGroups.config.groupPolicy === "allowlist") {
400	      const groupKeys = Object.keys(resolvedAfterGroups.config.groups ?? {});
401	      if (groupKeys.length > 0) {
402	        const wantsMentions = await prompter.confirm({
403	          message: "Require @mention to reply in IRC channels?",
404	          initialValue: true,
405	        });
406	        if (!wantsMentions) {
407	          const groups = resolvedAfterGroups.config.groups ?? {};
408	          const patched = Object.fromEntries(
409	            Object.entries(groups).map(([key, value]) => [
410	              key,
411	              { ...value, requireMention: false },
412	            ]),
413	          );
414	          next = updateIrcAccountConfig(next, accountId, { groups: patched });
415	        }
416	      }
417	    }
418	
419	    next = await promptIrcNickServConfig({
420	      cfg: next,
421	      prompter,
422	      accountId,
423	    });
424	    return { cfg: next };
425	  },
426	  completionNote: {
427	    title: "IRC next steps",
428	    lines: [
429	      "Next: restart gateway and verify status.",
430	      "Command: openclaw channels status --probe",
431	      `Docs: ${formatDocsLink("/channels/irc", "channels/irc")}`,
432	    ],
433	  },
434	  dmPolicy: ircDmPolicy,
435	  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
436	};
437	
438	export { ircSetupAdapter };
