// Per-account config stored under channels.pulseboard (or .accounts.<id>)
export type PulseboardAccountConfig = {
  name?: string;
  enabled?: boolean;
  serverUrl?: string; // e.g. "https://api.pulseboard.example"
  token?: string; // Bearer auth token
  userId?: string; // Bot's own user ID on the platform
  username?: string; // Bot's display username
  dmPolicy?: "open" | "pairing" | "allowlist" | "disabled";
  allowFrom?: Array<string | number>;
  boards?: string[]; // Board names to subscribe to (e.g. ["general", "tech"])
  requireMention?: boolean; // Whether board messages require @mention to reply
  defaultTo?: string; // Default outbound target
};

// Top-level pulseboard config (multi-account capable)
export type PulseboardConfig = PulseboardAccountConfig & {
  accounts?: Record<string, PulseboardAccountConfig>;
  defaultAccount?: string;
};

// Fully resolved account (all fields guaranteed or defaulted)
export type ResolvedPulseboardAccount = {
  accountId: string;
  enabled: boolean;
  configured: boolean; // true iff serverUrl && token && userId are non-empty
  name?: string;
  serverUrl: string;
  token: string;
  userId: string;
  username: string;
  config: PulseboardAccountConfig;
};

// Inbound message shape returned by the PulseBoard polling API
export type PulseboardMessage = {
  messageId: string;
  type: "direct" | "board";
  senderId: string;
  senderUsername: string;
  boardName?: string; // only present for type === "board"
  text: string;
  timestamp: number; // unix ms
};

// Status probe result
export type PulseboardProbe = {
  ok: boolean;
  latencyMs?: number;
  userId?: string;
  serverUrl?: string;
  error?: string;
};

// Narrowed OpenClaw config with pulseboard section
export type CoreConfig = {
  channels?: {
    pulseboard?: PulseboardConfig;
    [key: string]: unknown;
  };
  session?: {
    store?: string;
    [key: string]: unknown;
  };
  commands?: {
    useAccessGroups?: boolean;
    [key: string]: unknown;
  };
  [key: string]: unknown;
};

