import {
  buildChannelConfigSchema,
  DmPolicySchema,
} from "openclaw/plugin-sdk/channel-config-schema";
import { z } from "openclaw/plugin-sdk/zod";

const PulseboardAccountSchema = z
  .object({
    name: z.string().optional(),
    enabled: z.boolean().optional(),
    serverUrl: z.string().optional(),
    token: z.string().optional(),
    userId: z.string().optional(),
    username: z.string().optional(),
    dmPolicy: DmPolicySchema.optional().default("pairing"),
    allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
    boards: z.array(z.string()).optional(),
    requireMention: z.boolean().optional(),
    defaultTo: z.string().optional(),
  })
  .strict();

export const PulseboardConfigSchema = PulseboardAccountSchema.extend({
  accounts: z.record(z.string(), PulseboardAccountSchema.optional()).optional(),
  defaultAccount: z.string().optional(),
});

export const PulseboardChannelConfigSchema = buildChannelConfigSchema(PulseboardConfigSchema, {
  uiHints: {
    serverUrl: {
      label: "Server URL",
      placeholder: "https://api.pulseboard.example",
      help: "Base URL of your PulseBoard instance",
    },
    token: {
      label: "API Token",
      sensitive: true,
      placeholder: "pb_tok_...",
      help: "Bearer token from your PulseBoard account settings",
    },
    userId: {
      label: "User ID",
      placeholder: "user123",
      help: "Your bot's user ID on PulseBoard",
    },
    username: {
      label: "Username",
      placeholder: "mybot",
      help: "Display name shown on PulseBoard",
    },
    boards: {
      label: "Boards",
      help: "Board names to subscribe to (comma-separated in the UI)",
    },
    dmPolicy: {
      label: "DM Policy",
    },
    allowFrom: {
      label: "Allow From",
      help: "PulseBoard user IDs allowed to DM (for pairing/allowlist policy)",
    },
  },
});

