// Local implementation of chunkTextForOutbound.
// The SDK equivalent (openclaw/plugin-sdk text-chunking) is not in the public entrypoints,
// so PulseBoard implements this directly, mirroring the same newline-preferring break strategy.

/** Chunk outbound text into segments no longer than `limit`, preferring newline boundaries. */
export function chunkTextForOutbound(text: string, limit: number): string[] {
  if (!text) return [];
  if (limit <= 0) return [text];
  if (text.length <= limit) return [text];

  const chunks: string[] = [];
  let remaining = text;

  while (remaining.length > limit) {
    const window = remaining.slice(0, limit);
    const lastNewline = window.lastIndexOf("\n");
    const lastSpace = window.lastIndexOf(" ");
    // Prefer splitting at a newline, then a space, then hard-cut
    const breakAt = lastNewline > 0 ? lastNewline : lastSpace > 0 ? lastSpace : limit;
    chunks.push(remaining.slice(0, breakAt));
    remaining = remaining.slice(breakAt).replace(/^\s/, "");
  }

  if (remaining.length > 0) {
    chunks.push(remaining);
  }

  return chunks;
}

