import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseboardOptions = {
  cfg?: CoreConfig;
  accountId?: string | null;
  replyToId?: string | null;
};

export type SendPulseboardResult = {
  messageId: string;
  target: string;
};

/** Send a message to a PulseBoard target (DM or board). */
export async function sendMessagePulseboard(
  to: string,
  text: string,
  opts: SendPulseboardOptions = {},
): Promise<SendPulseboardResult> {
  const runtime = getPulseboardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseboardAccount({ cfg, accountId: opts.accountId });

  const normalized = normalizePulseboardTarget(to);
  if (!normalized) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }

  const clientOpts: PulseboardClientOptions = {
    serverUrl: account.serverUrl,
    token: account.token,
    userId: account.userId,
  };

  // Append reply reference when present
  const body = opts.replyToId ? `${text}\n\n[reply:${opts.replyToId}]` : text;

  if (isBoardTarget(normalized)) {
    const boardName = extractBoardName(normalized);
    const result = await sendPulseboardBoard(clientOpts, boardName, body);
    return { messageId: result.messageId, target: normalized };
  }

  const userId = extractDmUserId(normalized);
  const result = await sendPulseboardDm(clientOpts, userId, body);
  return { messageId: result.messageId, target: normalized };
}

