import {
  deliverFormattedTextWithAttachments,
  dispatchInboundDirectDmWithRuntime,
  logInboundDrop,
} from "openclaw/plugin-sdk/channel-inbound";
import { resolvePulseboardAccount } from "./accounts.js";
import { normalizePulseboardAllowlist } from "./normalize.js";
import { getPulseboardRuntime } from "./runtime.js";
import { sendMessagePulseboard } from "./send.js";
import type { CoreConfig, PulseboardMessage } from "./types.js";

const CHANNEL_ID = "pulseboard" as const;
const CHANNEL_LABEL = "PulseBoard";

export type PulseboardInboundContext = {
  cfg: CoreConfig;
  accountId: string;
  message: PulseboardMessage;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
};

export async function handlePulseboardInbound(ctx: PulseboardInboundContext): Promise<void> {
  const { cfg, accountId, message, statusSink } = ctx;
  const core = getPulseboardRuntime();
  const account = resolvePulseboardAccount({ cfg, accountId });

  const rawBody = message.text?.trim() ?? "";
  if (!rawBody) return;

  statusSink?.({ lastInboundAt: message.timestamp });

  const senderId = message.senderId;
  const dmPolicy = account.config.dmPolicy ?? "pairing";
  const isBoard = message.type === "board" && Boolean(message.boardName);
  const boardName = message.boardName ?? "";

  // Routing peer: for boards use the board name as the session key anchor,
  // for DMs use the sender ID so each user has their own session.
  const peerId = isBoard ? `board:${boardName}` : senderId;

  // Addresses used for context / envelope labeling
  const senderAddress = isBoard
    ? `pulseboard:board:${boardName}:${senderId}`
    : `pulseboard:${senderId}`;
  const recipientAddress = isBoard
    ? `pulseboard:board:${boardName}`
    : `pulseboard:${account.userId}`;
  const conversationLabel = isBoard
    ? `#${boardName}`
    : message.senderUsername || senderId;

  // Extra context to override ChatType for board messages
  const extraContext: Record<string, unknown> | undefined = isBoard
    ? { ChatType: "group", GroupSubject: boardName, SenderName: message.senderUsername || senderId }
    : { SenderName: message.senderUsername || senderId };

  // DM policy gate — boards are always dispatched (subscribed intentionally)
  if (!isBoard) {
    if (dmPolicy === "disabled") {
      logInboundDrop({
        log: (line) => core.logging?.getChildLogger().debug?.(line),
        channel: CHANNEL_ID,
        reason: "dmPolicy=disabled",
        target: senderId,
      });
      return;
    }

    if (dmPolicy !== "open") {
      const allowFrom = normalizePulseboardAllowlist(account.config.allowFrom);
      const normalizedSender = senderId.toLowerCase();
      const isAllowed =
        allowFrom.includes("*") ||
        allowFrom.includes(normalizedSender) ||
        (dmPolicy === "pairing" && (await checkPairingStore(core, accountId, normalizedSender)));

      if (!isAllowed) {
        if (dmPolicy === "pairing") {
          await issuePairingChallenge({
            core,
            cfg,
            accountId,
            senderId,
            senderUsername: message.senderUsername,
          });
        }
        logInboundDrop({
          log: (line) => core.logging?.getChildLogger().debug?.(line),
          channel: CHANNEL_ID,
          reason: `dmPolicy=${dmPolicy}`,
          target: senderId,
        });
        return;
      }
    }
  }

  await dispatchInboundDirectDmWithRuntime({
    cfg: cfg as Parameters<typeof dispatchInboundDirectDmWithRuntime>[0]["cfg"],
    runtime: core as Parameters<typeof dispatchInboundDirectDmWithRuntime>[0]["runtime"],
    channel: CHANNEL_ID,
    channelLabel: CHANNEL_LABEL,
    accountId,
    peer: { kind: "direct", id: peerId },
    senderId,
    senderAddress,
    recipientAddress,
    conversationLabel,
    rawBody,
    messageId: message.messageId,
    timestamp: message.timestamp,
    extraContext,
    deliver: async (payload) => {
      const replyTarget = isBoard ? `board:${boardName}` : `dm:${senderId}`;
      await deliverFormattedTextWithAttachments({
        payload,
        send: async ({ text, replyToId }) => {
          await sendMessagePulseboard(replyTarget, text, {
            cfg,
            accountId,
            replyToId: replyToId ?? undefined,
          });
          statusSink?.({ lastOutboundAt: Date.now() });
          core.channel.activity.record({
            channel: CHANNEL_ID,
            accountId,
            direction: "outbound",
          });
        },
      });
    },
    onRecordError: (err) => {
      core.logging?.getChildLogger().warn(`[pulseboard:${accountId}] session record error: ${String(err)}`);
    },
    onDispatchError: (err, info) => {
      core.logging?.getChildLogger().error(`[pulseboard:${accountId}] ${info.kind} dispatch error: ${String(err)}`);
    },
  });
}

/** Check if a sender is in the pairing store (approved). */
async function checkPairingStore(
  core: ReturnType<typeof getPulseboardRuntime>,
  accountId: string,
  senderId: string,
): Promise<boolean> {
  try {
    const stored = await core.channel.pairing.readAllowFromStore({
      channel: CHANNEL_ID,
      accountId,
    });
    const normalizedStore = (stored ?? []).map((e: string) => e.toLowerCase());
    return normalizedStore.includes(senderId);
  } catch {
    return false;
  }
}

/** Issue a pairing challenge to a new DM sender. */
async function issuePairingChallenge(params: {
  core: ReturnType<typeof getPulseboardRuntime>;
  cfg: CoreConfig;
  accountId: string;
  senderId: string;
  senderUsername?: string;
}): Promise<void> {
  const { core, cfg, accountId, senderId, senderUsername } = params;
  try {
    const reply = core.channel.pairing.buildPairingReply({
      senderId,
      senderIdLine: `Your PulseBoard user ID: ${senderId}`,
      meta: { name: senderUsername || undefined },
    });
    await params.core.channel.pairing.upsertPairingRequest({
      channel: CHANNEL_ID,
      accountId,
      senderId,
    });
    await sendMessagePulseboard(`dm:${senderId}`, reply, { cfg, accountId });
  } catch {
    // Best-effort — pairing challenge failures are non-fatal
  }
}

