import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseboardAccount } from "./accounts.js";
import { pollPulseboardUpdates } from "./client.js";
import { handlePulseboardInbound } from "./inbound.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";
import type { RuntimeEnv } from "./runtime-api.js";

const POLL_INTERVAL_MS = 2000;

export type MonitorPulseboardOptions = {
  accountId: string;
  config: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
};

/** Poll the PulseBoard updates API until aborted, routing inbound messages to core. */
export async function monitorPulseboardProvider(
  opts: MonitorPulseboardOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseboardRuntime();
  const { accountId, config, abortSignal, statusSink } = opts;

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  const account = resolvePulseboardAccount({ cfg: config, accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" ` +
        `(need serverUrl, token, and userId in channels.pulseboard).`,
    );
  }

  runtime.log?.(
    `[pulseboard:${accountId}] starting PulseBoard monitor (${account.serverUrl})`,
  );

  // Start from now; only receive messages arriving after startup
  let since = Date.now();
  let stopped = false;

  const loop = async () => {
    while (!abortSignal.aborted && !stopped) {
      try {
        const messages = await pollPulseboardUpdates(
          { serverUrl: account.serverUrl, token: account.token, userId: account.userId },
          since,
          abortSignal,
        );

        for (const message of messages) {
          if (message.timestamp > since) {
            since = message.timestamp;
          }
          // Skip messages from self
          if (message.senderId === account.userId) continue;

          core.channel.activity.record({
            channel: "pulseboard",
            accountId,
            direction: "inbound",
            at: message.timestamp,
          });

          await handlePulseboardInbound({
            cfg: config,
            accountId,
            message,
            statusSink,
          }).catch((err: unknown) => {
            runtime.error?.(
              `[pulseboard:${accountId}] inbound handler error: ${String(err)}`,
            );
          });
        }
      } catch (err) {
        if (abortSignal.aborted || stopped) break;
        runtime.error?.(`[pulseboard:${accountId}] poll error: ${String(err)}`);
      }

      // Wait before next poll cycle (abort-aware)
      await new Promise<void>((resolve) => {
        const timer = setTimeout(resolve, POLL_INTERVAL_MS);
        abortSignal.addEventListener(
          "abort",
          () => {
            clearTimeout(timer);
            resolve();
          },
          { once: true },
        );
      });
    }

    runtime.log?.(`[pulseboard:${accountId}] monitor stopped`);
  };

  // Start the loop in the background; the Promise is intentionally not awaited
  // here so that `runStoppablePassiveMonitor` can manage lifecycle.
  void loop();

  return {
    stop: () => {
      stopped = true;
    },
  };
}

