import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import {
  listPulseboardAccountIds,
  resolveDefaultPulseboardAccountId,
  resolvePulseboardAccount,
} from "./accounts.js";
import { normalizePulseboardAllowEntry } from "./normalize.js";
import type { CoreConfig, PulseboardAccountConfig } from "./types.js";

const channel = "pulseboard" as const;

// ── Config patch helpers ────────────────────────────────────────────────────

const setPulseboardTopLevelDmPolicy = createTopLevelChannelDmPolicySetter({ channel });
const setPulseboardTopLevelAllowFrom = createTopLevelChannelAllowFromSetter({ channel });

export function updatePulseboardAccountConfig(
  cfg: CoreConfig,
  accountId: string,
  patch: Partial<PulseboardAccountConfig>,
): CoreConfig {
  return patchScopedAccountConfig({
    cfg,
    channelKey: channel,
    accountId,
    patch,
    ensureChannelEnabled: false,
    ensureAccountEnabled: false,
  }) as CoreConfig;
}

export function setPulseboardDmPolicy(cfg: CoreConfig, dmPolicy: DmPolicy): CoreConfig {
  return setPulseboardTopLevelDmPolicy(cfg, dmPolicy) as CoreConfig;
}

export function setPulseboardAllowFrom(cfg: CoreConfig, allowFrom: string[]): CoreConfig {
  return setPulseboardTopLevelAllowFrom(cfg, allowFrom) as CoreConfig;
}

// ── Setup adapter (programmatic config apply) ───────────────────────────────

export const pulseboardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: ({ accountId }) => normalizeAccountId(accountId),
  applyAccountName: ({ cfg, accountId, name }) =>
    applyAccountNameToChannelSection({ cfg, channelKey: channel, accountId, name }),
  validateInput: createSetupInputPresenceValidator({
    whenNotUseEnv: [
      { someOf: ["serverUrl"], message: "PulseBoard requires a server URL." },
      { someOf: ["token"], message: "PulseBoard requires an API token." },
      { someOf: ["userId"], message: "PulseBoard requires a user ID." },
    ],
  }),
  applyAccountConfig: ({ cfg, accountId, input }) => {
    const namedConfig = applyAccountNameToChannelSection({
      cfg,
      channelKey: channel,
      accountId,
      name: (input as { name?: string }).name,
    });
    const patch: Partial<PulseboardAccountConfig> = {
      enabled: true,
      serverUrl: (input as { serverUrl?: string }).serverUrl?.trim(),
      token: (input as { token?: string }).token?.trim(),
      userId: (input as { userId?: string }).userId?.trim(),
      username: (input as { username?: string }).username?.trim(),
    };
    return patchScopedAccountConfig({
      cfg: namedConfig,
      channelKey: channel,
      accountId,
      patch,
    }) as CoreConfig;
  },
};

// ── DM policy section ───────────────────────────────────────────────────────

const pulseboardDmPolicy: ChannelSetupDmPolicy = {
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => (cfg as CoreConfig).channels?.pulseboard?.dmPolicy ?? "pairing",
  setPolicy: (cfg, policy) => setPulseboardDmPolicy(cfg as CoreConfig, policy),
  promptAllowFrom: async ({ cfg, prompter }) => {
    const existing = (cfg as CoreConfig).channels?.pulseboard?.allowFrom ?? [];
    const raw = String(
      await prompter.text({
        message: "PulseBoard allowFrom (user IDs, comma-separated)",
        placeholder: "alice, bob123",
        initialValue: existing.map(String).join(", "),
        validate: () => undefined,
      }),
    );
    const entries = raw
      .split(/[\n,;]+/g)
      .map((e) => normalizePulseboardAllowEntry(e))
      .filter(Boolean);
    return setPulseboardAllowFrom(cfg as CoreConfig, entries);
  },
};

// ── Setup wizard ────────────────────────────────────────────────────────────

export const pulseboardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs serverUrl + token + userId",
    configuredHint: "configured",
    unconfiguredHint: "needs serverUrl, token, and userId",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listPulseboardAccountIds(cfg as CoreConfig).some(
        (accountId) =>
          resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: [
      "PulseBoard needs a server URL, an API token, and your bot's user ID.",
      "Obtain a Bearer token from your PulseBoard account settings.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
    shouldShow: ({ cfg, accountId }) =>
      !resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
  },
  credentials: [],
  textInputs: [
    {
      inputKey: "serverUrl",
      message: "PulseBoard server URL",
      placeholder: "https://api.pulseboard.example",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).serverUrl || undefined,
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          serverUrl: value,
        }),
    },
    {
      inputKey: "token",
      message: "PulseBoard API token",
      placeholder: "pb_tok_...",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).token || undefined,
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          token: value,
        }),
    },
    {
      inputKey: "userId",
      message: "Bot user ID on PulseBoard",
      placeholder: "user123",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).userId || undefined,
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          userId: value,
        }),
    },
    {
      inputKey: "username",
      message: "Display username (optional)",
      placeholder: "mybot",
      required: false,
      applyEmptyValue: false,
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).username || undefined,
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          username: value || undefined,
        }),
    },
    {
      inputKey: "boards",
      message: "Board names to subscribe to (optional, comma-separated)",
      placeholder: "general, tech",
      required: false,
      applyEmptyValue: true,
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId }).config.boards?.join(", "),
      normalizeValue: ({ value }) =>
        String(value ?? "")
          .split(/[\n,;]+/g)
          .map((e) => e.trim())
          .filter(Boolean)
          .join(", "),
      applySet: async ({ cfg, accountId, value }) => {
        const boards = String(value ?? "")
          .split(/[\n,;]+/g)
          .map((e) => e.trim())
          .filter(Boolean);
        return updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          boards: boards.length > 0 ? boards : undefined,
        });
      },
    },
  ],
  allowFrom: createAllowFromSection({
    helpTitle: "PulseBoard allowlist",
    helpLines: [
      "Allowlist PulseBoard DMs by sender user ID.",
      "Examples: alice, user123",
      "Multiple entries: comma-separated.",
    ],
    message: "PulseBoard allowFrom (user IDs)",
    placeholder: "alice, bob123",
    invalidWithoutCredentialNote: "Use a PulseBoard user ID.",
    parseId: (raw) => {
      const normalized = normalizePulseboardAllowEntry(raw);
      return normalized || null;
    },
    apply: async ({ cfg, allowFrom }) => setPulseboardAllowFrom(cfg as CoreConfig, allowFrom),
  }),
  completionNote: {
    title: "PulseBoard next steps",
    lines: [
      "Next: restart gateway and verify status.",
      "Command: openclaw channels status --probe",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
  },
  dmPolicy: pulseboardDmPolicy,
  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
};

