import { describe, it, expect } from "vitest";
import {
  resolvePulseboardAccount,
  listPulseboardAccountIds,
} from "./accounts.js";
import {
  normalizePulseboardTarget,
  isBoardTarget,
  isDmTarget,
  extractBoardName,
  extractDmUserId,
  normalizePulseboardAllowEntry,
  looksLikePulseboardTargetId,
} from "./normalize.js";
import { chunkTextForOutbound } from "./chunk.js";
import type { CoreConfig } from "./types.js";

const baseCfg: CoreConfig = {
  channels: {
    pulseboard: {
      serverUrl: "https://pb.example",
      token: "tok_test",
      userId: "bot1",
      username: "testbot",
      dmPolicy: "pairing",
    },
  },
};

// ── accounts ──────────────────────────────────────────────────────────────

describe("accounts", () => {
  it("resolves default account", () => {
    const account = resolvePulseboardAccount({ cfg: baseCfg });
    expect(account.configured).toBe(true);
    expect(account.serverUrl).toBe("https://pb.example");
    expect(account.userId).toBe("bot1");
    expect(account.username).toBe("testbot");
  });

  it("reports unconfigured when fields missing", () => {
    const account = resolvePulseboardAccount({
      cfg: { channels: { pulseboard: {} } },
    });
    expect(account.configured).toBe(false);
  });

  it("reports unconfigured when token is missing", () => {
    const account = resolvePulseboardAccount({
      cfg: {
        channels: { pulseboard: { serverUrl: "https://pb.example", userId: "bot1" } },
      },
    });
    expect(account.configured).toBe(false);
  });

  it("lists account ids (default account)", () => {
    const ids = listPulseboardAccountIds(baseCfg);
    expect(ids).toContain("default");
  });

  it("lists named accounts", () => {
    const cfg: CoreConfig = {
      channels: {
        pulseboard: {
          accounts: {
            work: { serverUrl: "https://work.example", token: "tok", userId: "u1" },
            home: { serverUrl: "https://home.example", token: "tok2", userId: "u2" },
          },
        },
      },
    };
    const ids = listPulseboardAccountIds(cfg);
    expect(ids).toContain("work");
    expect(ids).toContain("home");
  });

  it("falls back to username = userId when username not set", () => {
    const cfg: CoreConfig = {
      channels: {
        pulseboard: { serverUrl: "https://pb.example", token: "tok", userId: "botX" },
      },
    };
    const account = resolvePulseboardAccount({ cfg });
    expect(account.username).toBe("botX");
  });
});

// ── normalize ─────────────────────────────────────────────────────────────

describe("normalizePulseboardTarget", () => {
  it("normalizes # board target", () => {
    expect(normalizePulseboardTarget("#general")).toBe("board:general");
  });

  it("normalizes board: prefix passthrough", () => {
    expect(normalizePulseboardTarget("board:tech")).toBe("board:tech");
  });

  it("normalizes @ dm target", () => {
    expect(normalizePulseboardTarget("@alice")).toBe("dm:alice");
  });

  it("normalizes dm: prefix passthrough", () => {
    expect(normalizePulseboardTarget("dm:bob")).toBe("dm:bob");
  });

  it("defaults bare string to dm", () => {
    expect(normalizePulseboardTarget("charlie")).toBe("dm:charlie");
  });

  it("strips pulseboard: channel prefix", () => {
    expect(normalizePulseboardTarget("pulseboard:#general")).toBe("board:general");
    expect(normalizePulseboardTarget("pulseboard:dm:alice")).toBe("dm:alice");
  });

  it("returns undefined for empty string", () => {
    expect(normalizePulseboardTarget("")).toBeUndefined();
    expect(normalizePulseboardTarget("   ")).toBeUndefined();
  });
});

describe("isBoardTarget / isDmTarget", () => {
  it("identifies board targets", () => {
    expect(isBoardTarget("board:x")).toBe(true);
    expect(isBoardTarget("#general")).toBe(true);
    expect(isBoardTarget("dm:x")).toBe(false);
  });

  it("identifies dm targets", () => {
    expect(isDmTarget("dm:x")).toBe(true);
    expect(isDmTarget("@alice")).toBe(true);
    expect(isDmTarget("board:x")).toBe(false);
  });
});

describe("extractBoardName", () => {
  it("extracts from canonical form", () => {
    expect(extractBoardName("board:general")).toBe("general");
  });
  it("extracts from # form", () => {
    expect(extractBoardName("#tech")).toBe("tech");
  });
});

describe("extractDmUserId", () => {
  it("extracts from canonical form", () => {
    expect(extractDmUserId("dm:alice")).toBe("alice");
  });
  it("extracts from @ form", () => {
    expect(extractDmUserId("@bob")).toBe("bob");
  });
});

describe("normalizePulseboardAllowEntry", () => {
  it("lowercases and strips dm: prefix", () => {
    expect(normalizePulseboardAllowEntry("dm:Alice")).toBe("alice");
    expect(normalizePulseboardAllowEntry("@Bob")).toBe("bob");
    expect(normalizePulseboardAllowEntry("Charlie")).toBe("charlie");
  });
});

describe("looksLikePulseboardTargetId", () => {
  it("accepts sigil forms", () => {
    expect(looksLikePulseboardTargetId("#board")).toBe(true);
    expect(looksLikePulseboardTargetId("@user")).toBe(true);
    expect(looksLikePulseboardTargetId("board:x")).toBe(true);
    expect(looksLikePulseboardTargetId("dm:y")).toBe(true);
  });
  it("accepts bare alphanumeric IDs", () => {
    expect(looksLikePulseboardTargetId("alice123")).toBe(true);
    expect(looksLikePulseboardTargetId("my-bot")).toBe(true);
  });
  it("rejects empty or too short strings", () => {
    expect(looksLikePulseboardTargetId("")).toBe(false);
    expect(looksLikePulseboardTargetId("a")).toBe(false);
  });
});

// ── chunkTextForOutbound ──────────────────────────────────────────────────

describe("chunkTextForOutbound", () => {
  it("returns single chunk when text fits", () => {
    expect(chunkTextForOutbound("hello world", 100)).toEqual(["hello world"]);
  });

  it("returns empty array for empty text", () => {
    expect(chunkTextForOutbound("", 100)).toEqual([]);
  });

  it("splits at newline boundary", () => {
    const text = "line one\nline two that is long enough to force a split";
    const chunks = chunkTextForOutbound(text, 20);
    expect(chunks.length).toBeGreaterThan(1);
    // All chunks should be within the limit
    for (const chunk of chunks) {
      expect(chunk.length).toBeLessThanOrEqual(20);
    }
  });

  it("splits at space boundary when no newline available", () => {
    const text = "word1 word2 word3 word4 word5 word6 word7 word8";
    const chunks = chunkTextForOutbound(text, 15);
    for (const chunk of chunks) {
      expect(chunk.length).toBeLessThanOrEqual(15);
    }
  });

  it("hard-cuts when no break point found", () => {
    const text = "abcdefghijklmnopqrstuvwxyz";
    const chunks = chunkTextForOutbound(text, 10);
    expect(chunks.every((c) => c.length <= 10)).toBe(true);
    expect(chunks.join("")).toBe(text);
  });
});

// ── pulseboardPlugin shape ────────────────────────────────────────────────
// NOTE: Importing pulseboardPlugin requires the full runtime to be initialized
// (openclaw/plugin-sdk/core imports createChatChannelPlugin, etc.). These shape
// checks are kept lightweight and only test static properties.
describe("pulseboardPlugin shape (lazy import)", () => {
  it("exports a plugin with correct id and capabilities", async () => {
    const { pulseboardPlugin } = await import("./channel.js");
    expect(pulseboardPlugin.id).toBe("pulseboard");
    // Capabilities are defined on the plugin object
    expect(
      (pulseboardPlugin as unknown as { capabilities: { chatTypes: string[] } }).capabilities
        .chatTypes,
    ).toContain("direct");
    expect(
      (pulseboardPlugin as unknown as { capabilities: { chatTypes: string[] } }).capabilities
        .chatTypes,
    ).toContain("group");
  });
});

